sql:
SELECT utility_name
FROM utility_companies
WHERE utility_id = 1;

SELECT peak_demand, avg_consumption, caiso_data
FROM grid_performance
WHERE date = '2021-01-02';

SELECT SUM(storage_capacity) AS total_storage_capacity
FROM energy_storage
WHERE date = '2023-05-02';

external_knowledge:
residential rate type refers to the energy rate applied to homes and household use; 
 utility_id uniquely identifies each utility company in the database; 
 date '2023-05-01' is a specific date in the format 'YYYY-MM-DD'.

sql:
SELECT utility_id, cost_per_kwh
FROM energy_costs
WHERE rate_type = 'residential' AND date = '2023-05-01';

SELECT AVG(cost_per_kwh) AS average_cost_per_kwh
FROM energy_costs
WHERE utility_id = 0;

SELECT AVG(forecasted_demand) AS average_forecasted_demand
FROM demand_forecasts
WHERE utility_id = 0;
